import math

def calculate_distance(x1, y1, x2, y2):
    return math.sqrt((x2 - x1)**2 + (y2 - y1)**2)

def count_habitats(num_habitats, k, habitats):
    count = 0
    for habitat in habitats:
        if habitat <= k:
            count += 1
    return count

def minRadiusForPark(n, k, habitats):
    habitats.sort(key=lambda x: x[0]**2 + x[1]**2)
    low = 0
    high = math.sqrt(habitats[-1][0]**2 + habitats[-1][1]**2)

    while low < high:
        mid = (low + high) / 2
        count = 0
        for habitat in habitats:
            if habitat[0]**2 + habitat[1]**2 <= mid**2:
                count += 1
        if count < k:
            low = mid + 0.000001
        else:
            high = mid

    return high

x1, y1 = map(int, input().split())
x2, y2 = map(int, input().split())
