print(distance)

num_habitats, k, *habitats = map(int, input().split())
print(count_habitats(num_habitats, k, habitats))

n, k = 8, 4
habitats = [(-3, 1), (-4, 4), (1, 5), (2, 2), (2, -2), (-2, -4), (-1, -1), (-6, 0)]
