def calculate_happiness(n, k, happiness, tours):
    dp = [0] * (n+1)
    for i in range(1, n+1):
        for j in range(i):
            tickets_required = abs(i - j) - 1
            if tickets_required <= k:
                dp[i] = max(dp[i], dp[j] + happiness[i-1])
    return max(dp)

def calculate_happiness_sum(n, m, h, tours):
    total_sum = 0
    for tour in tours:
        u, v, t = tour
        total_sum += h[u-1] + h[v-1] + t
    return total_sum

